CREATE OR REPLACE FUNCTION public.calc_classificacao(idade integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF idade IS NULL THEN RETURN 'adulto';
  ELSIF idade < 4 THEN RETURN 'bebe';
  ELSIF idade < 12 THEN RETURN 'crianca';
  ELSIF idade < 18 THEN RETURN 'adolescente';
  ELSE RETURN 'adulto';
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.calc_idade(data_nasc date)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF data_nasc IS NULL THEN RETURN NULL; END IF;
  RETURN EXTRACT(YEAR FROM age(CURRENT_DATE, data_nasc))::INTEGER;
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_campos_aluno()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_curso_nome TEXT;
  v_is_banda BOOLEAN := false;
  v_has_other_enrollment BOOLEAN := false;
BEGIN
  -- Calcular idade e classificação EMLA/LAMK
  IF NEW.data_nascimento IS NOT NULL THEN
    NEW.idade_atual := EXTRACT(YEAR FROM AGE(CURRENT_DATE, NEW.data_nascimento))::INTEGER;
    NEW.classificacao := CASE
      WHEN NEW.idade_atual < 12 THEN 'LAMK'
      ELSE 'EMLA'
    END;
  ELSE
    NEW.idade_atual := NULL;
    NEW.classificacao := NULL;
  END IF;

  -- Calcular tempo de permanência em meses
  IF NEW.data_matricula IS NOT NULL THEN
    IF NEW.data_saida IS NOT NULL THEN
      NEW.tempo_permanencia_meses := (
        EXTRACT(YEAR FROM AGE(NEW.data_saida, NEW.data_matricula)) * 12 +
        EXTRACT(MONTH FROM AGE(NEW.data_saida, NEW.data_matricula))
      )::INTEGER;
    ELSE
      NEW.tempo_permanencia_meses := (
        EXTRACT(YEAR FROM AGE(CURRENT_DATE, NEW.data_matricula)) * 12 +
        EXTRACT(MONTH FROM AGE(CURRENT_DATE, NEW.data_matricula))
      )::INTEGER;
    END IF;
  ELSE
    NEW.tempo_permanencia_meses := NULL;
  END IF;

  -- Auto-detecção de banda e segundo curso (apenas INSERT)
  IF TG_OP = 'INSERT' AND COALESCE(NEW.tipo_matricula_id, 1) IN (1, 2) THEN

    IF NEW.curso_id IS NOT NULL THEN
      SELECT nome INTO v_curso_nome
      FROM cursos
      WHERE id = NEW.curso_id;
      v_is_banda := (v_curso_nome ILIKE '%banda%');
    END IF;

    IF NEW.nome IS NOT NULL AND NEW.unidade_id IS NOT NULL THEN
      SELECT EXISTS(
        SELECT 1 FROM alunos
        WHERE nome_normalizado = UPPER(TRIM(NEW.nome))
          AND unidade_id = NEW.unidade_id
          AND status = 'ativo'
          AND id IS DISTINCT FROM NEW.id
      ) INTO v_has_other_enrollment;
    END IF;

    IF v_is_banda THEN
      NEW.tipo_matricula_id := 5;
      IF v_has_other_enrollment THEN
        NEW.is_segundo_curso := true;
      END IF;
    ELSIF v_has_other_enrollment THEN
      NEW.tipo_matricula_id := 2;
      NEW.is_segundo_curso := true;
    END IF;

  END IF;

  NEW.updated_at := NOW();
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_comissao_venda()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_comissao_percentual NUMERIC;
  v_valor_comissao NUMERIC;
  v_carteira_id INTEGER;
  v_saldo_atual NUMERIC;
BEGIN
  -- Só processa se a venda tem vendedor (vendedor_id)
  IF NEW.vendedor_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Buscar percentual de comissão das configurações (global, sem filtro por unidade)
  SELECT COALESCE(
    (SELECT valor::NUMERIC FROM loja_configuracoes WHERE chave = 'comissao_farmer_venda' LIMIT 1),
    5.0 -- Padrão 5%
  ) INTO v_comissao_percentual;

  -- Calcular valor da comissão
  v_valor_comissao := (NEW.total * v_comissao_percentual) / 100;

  -- Buscar ou criar carteira do colaborador
  SELECT id, saldo INTO v_carteira_id, v_saldo_atual
  FROM loja_carteira
  WHERE colaborador_id = NEW.vendedor_id AND tipo_titular = 'farmer'
  LIMIT 1;

  IF v_carteira_id IS NULL THEN
    -- Criar carteira
    INSERT INTO loja_carteira (tipo_titular, colaborador_id, unidade_id, saldo, moedas_la)
    VALUES ('farmer', NEW.vendedor_id, NEW.unidade_id, 0, 0)
    RETURNING id, saldo INTO v_carteira_id, v_saldo_atual;
  END IF;

  -- Atualizar saldo da carteira
  UPDATE loja_carteira
  SET saldo = saldo + v_valor_comissao,
      updated_at = NOW()
  WHERE id = v_carteira_id;

  -- Registrar movimentação com colunas corretas
  INSERT INTO loja_carteira_movimentacoes (carteira_id, tipo, valor, saldo_apos, referencia_tipo, referencia_id, descricao, created_at)
  VALUES (v_carteira_id, 'comissao_venda', v_valor_comissao, v_saldo_atual + v_valor_comissao, 'venda', NEW.id, 'Comissão de venda #' || NEW.id, NOW());

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_health_score_aluno(p_aluno_id integer)
 RETURNS TABLE(score integer, status character varying, detalhes jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_aluno RECORD;
  v_feedback VARCHAR;
  v_config RECORD;
  v_score NUMERIC := 0;
  v_status VARCHAR;
  v_detalhes JSONB := '[]'::JSONB;
  v_contrib JSONB;
  v_pag_score NUMERIC;
  v_tempo_score NUMERIC;
  v_fase_score NUMERIC;
  v_fb_score NUMERIC;
  v_pres_score NUMERIC;
  v_tempo INTEGER;
  v_pres INTEGER;
BEGIN
  -- Buscar dados do aluno
  SELECT * INTO v_aluno FROM alunos WHERE id = p_aluno_id;

  IF NOT FOUND THEN
    RETURN QUERY SELECT 0::INTEGER, 'erro'::VARCHAR, '{"erro": "Aluno não encontrado"}'::JSONB;
    RETURN;
  END IF;

  -- Buscar configuração de pesos (global ou por unidade)
  SELECT * INTO v_config 
  FROM config_health_score_aluno 
  WHERE unidade_id = v_aluno.unidade_id OR unidade_id IS NULL
  ORDER BY unidade_id NULLS LAST
  LIMIT 1;

  -- Fallback para pesos padrão se não houver config
  IF NOT FOUND THEN
    v_config.peso_pagamento := 30;
    v_config.peso_tempo_casa := 20;
    v_config.peso_fase_jornada := 20;
    v_config.peso_feedback_professor := 20;
    v_config.peso_presenca := 10;
    v_config.limite_saudavel := 70;
    v_config.limite_atencao := 40;
  END IF;

  -- Buscar último feedback do professor
  SELECT feedback INTO v_feedback
  FROM aluno_feedback_professor
  WHERE aluno_id = p_aluno_id
  ORDER BY competencia DESC, respondido_em DESC
  LIMIT 1;

  -- 1. PAGAMENTO (peso configurável, default 30%)
  v_pag_score := CASE v_aluno.status_pagamento
    WHEN 'em_dia' THEN 100
    WHEN 'atrasado' THEN 50
    ELSE 0 -- inadimplente
  END;
  v_score := v_score + (v_pag_score * v_config.peso_pagamento / 100);
  v_contrib := jsonb_build_object('fator', 'Pagamento', 'valor', COALESCE(v_aluno.status_pagamento, 'sem info'), 'score', v_pag_score, 'peso', v_config.peso_pagamento, 'contribuicao', ROUND(v_pag_score * v_config.peso_pagamento / 100, 1));
  v_detalhes := v_detalhes || v_contrib;

  -- 2. TEMPO DE CASA (peso configurável, default 20%)
  v_tempo := COALESCE(v_aluno.tempo_permanencia_meses, 0);
  v_tempo_score := CASE 
    WHEN v_tempo > 24 THEN 100
    WHEN v_tempo > 12 THEN 80
    WHEN v_tempo > 6 THEN 60
    WHEN v_tempo > 3 THEN 40
    ELSE 20
  END;
  v_score := v_score + (v_tempo_score * v_config.peso_tempo_casa / 100);
  v_contrib := jsonb_build_object('fator', 'Tempo de Casa', 'valor', v_tempo || ' meses', 'score', v_tempo_score, 'peso', v_config.peso_tempo_casa, 'contribuicao', ROUND(v_tempo_score * v_config.peso_tempo_casa / 100, 1));
  v_detalhes := v_detalhes || v_contrib;

  -- 3. FASE DA JORNADA (peso configurável, default 20%)
  v_fase_score := CASE 
    WHEN v_tempo >= 9 THEN 100  -- Renovação (veterano)
    WHEN v_tempo >= 6 THEN 80   -- Encantamento
    WHEN v_tempo >= 3 THEN 60   -- Consolidação
    ELSE 40                      -- Onboarding (risco maior)
  END;
  v_score := v_score + (v_fase_score * v_config.peso_fase_jornada / 100);
  v_contrib := jsonb_build_object('fator', 'Fase Jornada', 'valor', 
    CASE 
      WHEN v_tempo >= 9 THEN 'Renovação'
      WHEN v_tempo >= 6 THEN 'Encantamento'
      WHEN v_tempo >= 3 THEN 'Consolidação'
      ELSE 'Onboarding'
    END, 
    'score', v_fase_score, 'peso', v_config.peso_fase_jornada, 'contribuicao', ROUND(v_fase_score * v_config.peso_fase_jornada / 100, 1));
  v_detalhes := v_detalhes || v_contrib;

  -- 4. FEEDBACK DO PROFESSOR (peso configurável, default 20%)
  v_fb_score := CASE v_feedback
    WHEN 'verde' THEN 100
    WHEN 'amarelo' THEN 50
    WHEN 'vermelho' THEN 0
    ELSE 50 -- Sem feedback = neutro
  END;
  v_score := v_score + (v_fb_score * v_config.peso_feedback_professor / 100);
  v_contrib := jsonb_build_object('fator', 'Feedback Professor', 'valor', COALESCE(v_feedback, 'sem feedback'), 'score', v_fb_score, 'peso', v_config.peso_feedback_professor, 'contribuicao', ROUND(v_fb_score * v_config.peso_feedback_professor / 100, 1));
  v_detalhes := v_detalhes || v_contrib;

  -- 5. PRESENÇA (peso configurável, default 10%)
  v_pres := COALESCE(v_aluno.percentual_presenca, 75); -- Default 75% se não tiver dado
  v_pres_score := LEAST(100, v_pres);
  v_score := v_score + (v_pres_score * v_config.peso_presenca / 100);
  v_contrib := jsonb_build_object('fator', 'Presença', 'valor', v_pres || '%', 'score', v_pres_score, 'peso', v_config.peso_presenca, 'contribuicao', ROUND(v_pres_score * v_config.peso_presenca / 100, 1));
  v_detalhes := v_detalhes || v_contrib;

  -- Determinar status baseado nos limites configurados
  v_status := CASE 
    WHEN v_score >= v_config.limite_saudavel THEN 'saudavel'
    WHEN v_score >= v_config.limite_atencao THEN 'atencao'
    ELSE 'critico'
  END;

  RETURN QUERY SELECT ROUND(v_score)::INTEGER, v_status, v_detalhes;
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_health_score_alunos_batch(p_unidade_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(total_processados integer, saudaveis integer, atencao integer, criticos integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_count INTEGER := 0;
  v_saudaveis INTEGER := 0;
  v_atencao INTEGER := 0;
  v_criticos INTEGER := 0;
  v_aluno RECORD;
  v_result RECORD;
BEGIN
  FOR v_aluno IN 
    SELECT id FROM alunos 
    WHERE status IN ('ativo', 'trancado')
      AND (p_unidade_id IS NULL OR unidade_id = p_unidade_id)
      AND (is_segundo_curso IS NULL OR is_segundo_curso = false)
  LOOP
    SELECT * INTO v_result FROM calcular_health_score_aluno(v_aluno.id);

    UPDATE alunos SET 
      health_score_numerico = v_result.score,
      health_score = v_result.status,
      health_score_updated_at = now()
    WHERE id = v_aluno.id;

    v_count := v_count + 1;

    IF v_result.status = 'saudavel' THEN
      v_saudaveis := v_saudaveis + 1;
    ELSIF v_result.status = 'atencao' THEN
      v_atencao := v_atencao + 1;
    ELSE
      v_criticos := v_criticos + 1;
    END IF;
  END LOOP;

  RETURN QUERY SELECT v_count, v_saudaveis, v_atencao, v_criticos;
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_pontos_perdidos_com_tolerancia(p_professor_id integer, p_unidade_id uuid, p_criterio_id integer, p_competencia character varying)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_total_ocorrencias INTEGER;
  v_tolerancia INTEGER;
  v_pontos_perda INTEGER;
  v_ocorrencias_alem_tolerancia INTEGER;
BEGIN
  -- Buscar dados do critério
  SELECT COALESCE(c.tolerancia, 0), COALESCE(c.pontos_perda, 0)
  INTO v_tolerancia, v_pontos_perda
  FROM professor_360_criterios c
  WHERE c.id = p_criterio_id;

  -- Contar ocorrências do mês
  SELECT COUNT(*)::INTEGER INTO v_total_ocorrencias
  FROM professor_360_ocorrencias o
  WHERE o.professor_id = p_professor_id
    AND o.unidade_id = p_unidade_id
    AND o.criterio_id = p_criterio_id
    AND o.competencia = p_competencia;

  -- Calcular quantas ocorrências estão além da tolerância
  v_ocorrencias_alem_tolerancia := GREATEST(0, v_total_ocorrencias - v_tolerancia);

  -- Retornar pontos perdidos (só desconta após tolerância)
  RETURN v_ocorrencias_alem_tolerancia * v_pontos_perda;
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_reajuste_renovacao()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF NEW.valor_parcela_anterior IS NOT NULL AND NEW.valor_parcela_anterior > 0 THEN
        NEW.percentual_reajuste := ROUND(
            ((NEW.valor_parcela_novo - NEW.valor_parcela_anterior) / NEW.valor_parcela_anterior) * 100, 
            2
        );
    ELSE
        NEW.percentual_reajuste := 0;
    END IF;
    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.calcular_variacao(valor_atual numeric, valor_anterior numeric)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF valor_anterior = 0 OR valor_anterior IS NULL THEN
        RETURN 0;
    END IF;
    RETURN ROUND(((valor_atual - valor_anterior) / valor_anterior * 100)::NUMERIC, 2);
END;
$function$

CREATE OR REPLACE FUNCTION public.creditar_lalita_matricula()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_valor_lalita NUMERIC;
  v_carteira_id INTEGER;
  v_professor_id INTEGER;
BEGIN
  -- Só processa se tem professor indicador
  IF NEW.professor_indicador_id IS NULL THEN
    RETURN NEW;
  END IF;

  v_professor_id := NEW.professor_indicador_id;

  -- Buscar valor da Lalita nas configurações
  SELECT COALESCE(
    (SELECT valor::NUMERIC FROM loja_configuracoes WHERE chave = 'valor_moeda_la' LIMIT 1),
    30.0 -- Padrão R$ 30
  ) INTO v_valor_lalita;

  -- Buscar ou criar carteira do professor
  SELECT id INTO v_carteira_id
  FROM loja_carteira
  WHERE professor_id = v_professor_id AND tipo_titular = 'professor'
  LIMIT 1;

  IF v_carteira_id IS NULL THEN
    -- Criar carteira
    INSERT INTO loja_carteira (tipo_titular, professor_id, unidade_id, saldo, moedas_la)
    VALUES ('professor', v_professor_id, NEW.unidade_id, 0, 0)
    RETURNING id INTO v_carteira_id;
  END IF;

  -- Atualizar carteira: +1 Lalita e +valor em saldo
  UPDATE loja_carteira
  SET moedas_la = moedas_la + 1,
      saldo = saldo + v_valor_lalita,
      updated_at = NOW()
  WHERE id = v_carteira_id;

  -- Registrar movimentação
  INSERT INTO loja_carteira_movimentacoes (carteira_id, tipo, valor, referencia, created_at)
  VALUES (v_carteira_id, 'lalita', v_valor_lalita, 'Matrícula ' || COALESCE(NEW.aluno_nome, '#' || NEW.id), NOW());

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.criar_checklist_from_template(p_template_id uuid, p_colaborador_id integer, p_unidade_id uuid, p_titulo character varying DEFAULT NULL::character varying, p_data_prazo date DEFAULT NULL::date)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_template RECORD;
  v_checklist_id UUID;
  v_item JSONB;
  v_parent_id UUID;
  v_sub JSONB;
BEGIN
  -- Buscar template
  SELECT * INTO v_template FROM farmer_checklist_templates WHERE id = p_template_id AND ativo = true;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Template não encontrado ou inativo';
  END IF;

  -- Criar checklist
  INSERT INTO farmer_checklists (
    unidade_id, colaborador_id, titulo, descricao, tipo, template_id, data_prazo
  ) VALUES (
    p_unidade_id,
    p_colaborador_id,
    COALESCE(p_titulo, v_template.nome),
    v_template.descricao,
    'template',
    p_template_id,
    p_data_prazo
  ) RETURNING id INTO v_checklist_id;

  -- Criar itens a partir do JSON do template
  FOR v_item IN SELECT * FROM jsonb_array_elements(v_template.itens)
  LOOP
    INSERT INTO farmer_checklist_items (
      checklist_id, descricao, canal, ordem
    ) VALUES (
      v_checklist_id,
      v_item->>'descricao',
      v_item->>'canal',
      COALESCE((v_item->>'ordem')::INTEGER, 0)
    ) RETURNING id INTO v_parent_id;

    -- Criar sub-itens se existirem
    IF v_item ? 'subs' AND jsonb_array_length(v_item->'subs') > 0 THEN
      FOR v_sub IN SELECT * FROM jsonb_array_elements(v_item->'subs')
      LOOP
        INSERT INTO farmer_checklist_items (
          checklist_id, descricao, canal, parent_id, ordem
        ) VALUES (
          v_checklist_id,
          v_sub->>'descricao',
          v_sub->>'canal',
          v_parent_id,
          COALESCE((v_sub->>'ordem')::INTEGER, 0)
        );
      END LOOP;
    END IF;
  END LOOP;

  RETURN v_checklist_id;
END;
$function$

