CREATE OR REPLACE FUNCTION public.estornar_venda(p_venda_id integer, p_motivo text, p_via_audit text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_venda          loja_vendas%ROWTYPE;
  v_item           RECORD;
  v_saldo_atual    INT;
  v_saldo_apos     INT;
  v_total_venda    NUMERIC;
  v_perc_comissao  NUMERIC := 0.05;
  v_comissao       NUMERIC := 0;
  v_itens_json     JSONB   := '[]'::JSONB;
  v_item_json      JSONB;
BEGIN
  IF p_motivo IS NULL OR TRIM(p_motivo) = '' THEN
    RAISE EXCEPTION 'motivo_obrigatorio' USING HINT = 'O motivo do estorno nao pode ser vazio';
  END IF;

  IF p_via_audit IS NULL OR TRIM(p_via_audit) = '' THEN
    RAISE EXCEPTION 'via_audit_obrigatorio' USING HINT = 'via_audit nao pode ser vazio';
  END IF;

  SELECT * INTO v_venda FROM loja_vendas WHERE id = p_venda_id FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'venda_nao_encontrada' USING HINT = 'Venda nao existe';
  END IF;

  IF v_venda.status = 'estornada' THEN
    RAISE EXCEPTION 'venda_ja_estornada' USING HINT = 'A venda ja foi estornada anteriormente';
  END IF;

  v_total_venda := v_venda.total;

  FOR v_item IN
    SELECT vi.produto_id, vi.variacao_id, vi.quantidade, vi.preco_unitario,
           p.nome AS produto_nome
    FROM loja_vendas_itens vi
    JOIN loja_produtos p ON p.id = vi.produto_id
    WHERE vi.venda_id = p_venda_id
  LOOP
    SELECT COALESCE(quantidade, 0) INTO v_saldo_atual
    FROM loja_estoque
    WHERE produto_id = v_item.produto_id
      AND unidade_id = v_venda.unidade_id
      AND (variacao_id IS NOT DISTINCT FROM v_item.variacao_id);

    v_saldo_apos := COALESCE(v_saldo_atual, 0) + v_item.quantidade;

    UPDATE loja_estoque
    SET quantidade = v_saldo_apos,
        updated_at = NOW()
    WHERE produto_id = v_item.produto_id
      AND unidade_id = v_venda.unidade_id
      AND (variacao_id IS NOT DISTINCT FROM v_item.variacao_id);

    IF NOT FOUND THEN
      INSERT INTO loja_estoque (produto_id, unidade_id, variacao_id, quantidade, updated_at)
      VALUES (v_item.produto_id, v_venda.unidade_id, v_item.variacao_id, v_item.quantidade, NOW());
      v_saldo_apos := v_item.quantidade;
    END IF;

    INSERT INTO loja_movimentacoes_estoque (
      produto_id, variacao_id, unidade_id,
      tipo, quantidade, saldo_apos,
      referencia_id, observacoes, created_at
    ) VALUES (
      v_item.produto_id, v_item.variacao_id, v_venda.unidade_id,
      'estorno', v_item.quantidade, v_saldo_apos,
      p_venda_id, 'Estorno venda #' || p_venda_id || ' - ' || p_motivo, NOW()
    );

    v_item_json := jsonb_build_object(
      'produto_id',    v_item.produto_id,
      'produto_nome',  v_item.produto_nome,
      'variacao_id',   v_item.variacao_id,
      'quantidade',    v_item.quantidade,
      'saldo_apos',    v_saldo_apos
    );
    v_itens_json := v_itens_json || jsonb_build_array(v_item_json);
  END LOOP;

  IF v_venda.professor_indicador_id IS NOT NULL AND v_total_venda > 0 THEN
    SELECT COALESCE(valor::NUMERIC / 100, 0.05) INTO v_perc_comissao
    FROM loja_configuracoes
    WHERE chave = 'comissao_professor_pct'
    LIMIT 1;

    v_comissao := ROUND(v_total_venda * v_perc_comissao, 2);

    IF v_comissao > 0 THEN
      UPDATE loja_carteira
      SET saldo = saldo - v_comissao,
          updated_at = NOW()
      WHERE professor_id = v_venda.professor_indicador_id;

      INSERT INTO loja_carteira_movimentacoes (
        professor_id, tipo, valor, referencia_id,
        descricao, created_at
      ) VALUES (
        v_venda.professor_indicador_id,
        'debito',
        v_comissao,
        p_venda_id,
        'Estorno de comissao - venda #' || p_venda_id,
        NOW()
      );
    END IF;
  END IF;

  UPDATE loja_vendas
  SET status          = 'estornada',
      estornada_em    = NOW(),
      motivo_estorno  = p_motivo,
      observacoes     = COALESCE(observacoes, '') || ' | ESTORNADA por ' || p_via_audit || ': ' || p_motivo
  WHERE id = p_venda_id;

  RETURN jsonb_build_object(
    'venda_id',           p_venda_id,
    'itens_revertidos',   v_itens_json,
    'comissao_debitada',  v_comissao,
    'estornada_em',       NOW()
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.exec_readonly_sql(query text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  result jsonb;
  clean_query text;
BEGIN
  clean_query := upper(trim(query));

  -- Only allow SELECT
  IF NOT starts_with(clean_query, 'SELECT') THEN
    RAISE EXCEPTION 'Somente queries SELECT sao permitidas';
  END IF;

  -- Block dangerous keywords
  IF clean_query ~ '(INSERT|UPDATE|DELETE|DROP|ALTER|CREATE|TRUNCATE|GRANT|REVOKE|COPY)\s' THEN
    RAISE EXCEPTION 'Operacao nao permitida';
  END IF;

  EXECUTE format('SELECT jsonb_agg(row_to_json(t)) FROM (%s) t', query) INTO result;

  RETURN COALESCE(result, '[]'::jsonb);
END;
$function$

CREATE OR REPLACE FUNCTION public.executar_query_auditoria(p_sql text)
 RETURNS SETOF jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_lower TEXT;
BEGIN
  -- regexp_replace remove qualquer whitespace inicial/final (espaço, tab, newline)
  v_lower := lower(regexp_replace(p_sql, '^\s+|\s+$', '', 'g'));

  IF v_lower NOT LIKE 'select%' AND v_lower NOT LIKE 'with%' THEN
    RAISE EXCEPTION 'executar_query_auditoria: apenas SELECT/WITH permitido';
  END IF;
  IF position(';' IN v_lower) > 0 AND position(';' IN v_lower) < length(v_lower) - 1 THEN
    RAISE EXCEPTION 'executar_query_auditoria: statement chaining bloqueado';
  END IF;

  RETURN QUERY EXECUTE format('SELECT to_jsonb(t) FROM (%s) t', regexp_replace(p_sql, ';\s*$', '', 'g'));
END;
$function$

CREATE OR REPLACE FUNCTION public.executar_query_readonly(query_sql text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  resultado jsonb;
BEGIN
  IF NOT (trim(query_sql) ~* '^\s*SELECT') THEN
    RAISE EXCEPTION 'Apenas consultas SELECT são permitidas';
  END IF;

  IF query_sql ~* '\b(INSERT|UPDATE|DELETE|DROP|ALTER|TRUNCATE|CREATE|GRANT|REVOKE)\b' THEN
    RAISE EXCEPTION 'Operação não permitida. Apenas SELECT.';
  END IF;

  -- Envolve a query do usuário numa subquery com LIMIT 50 de segurança
  EXECUTE format('SELECT jsonb_agg(row_to_json(sub)) FROM (SELECT * FROM (%s) _inner LIMIT 50) sub', query_sql)
    INTO resultado;

  RETURN COALESCE(resultado, '[]'::jsonb);
END;
$function$

CREATE OR REPLACE FUNCTION public.execute_bi_query_lamusic(query_text text, p_unidade_id uuid DEFAULT NULL::uuid, max_rows integer DEFAULT 200)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE result JSONB;
BEGIN
  IF p_unidade_id IS NOT NULL THEN
    BEGIN
      EXECUTE format(
        'SELECT jsonb_agg(row_to_json(t)) FROM (
          SELECT * FROM (%s) sub WHERE unidade_id = %L LIMIT %s
        ) t',
        query_text, p_unidade_id, max_rows
      ) INTO result;
    EXCEPTION WHEN undefined_column THEN
      -- Coluna unidade_id não existe no resultado — executar sem filtro
      EXECUTE format(
        'SELECT jsonb_agg(row_to_json(t)) FROM (SELECT * FROM (%s) sub LIMIT %s) t',
        query_text, max_rows
      ) INTO result;
    END;
  ELSE
    EXECUTE format(
      'SELECT jsonb_agg(row_to_json(t)) FROM (SELECT * FROM (%s) sub LIMIT %s) t',
      query_text, max_rows
    ) INTO result;
  END IF;
  RETURN COALESCE(result, '[]'::jsonb);
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('error', SQLERRM, 'detail', SQLSTATE);
END;
$function$

