  INSERT INTO professor_360_ocorrencias_log (
    ocorrencia_id, acao, usuario_id, usuario_nome, justificativa, dados_anteriores, dados_novos
  ) VALUES (
    NEW.id,
    'criado',
    v_usuario_id,
    COALESCE(v_usuario_nome, 'Sistema'),
    NULL,
    NULL,
    row_to_json(NEW)::jsonb
  );

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_comparativo_anos(p_ano_atual integer, p_ano_anterior integer)
 RETURNS TABLE(metrica character varying, valor_anterior numeric, valor_atual numeric, variacao numeric)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_alunos_atual INTEGER;
    v_alunos_anterior INTEGER;
    v_matriculas_atual INTEGER;
    v_matriculas_anterior INTEGER;
    v_evasoes_atual INTEGER;
    v_evasoes_anterior INTEGER;
    v_churn_atual NUMERIC;
    v_churn_anterior NUMERIC;
    v_ticket_atual NUMERIC;
    v_ticket_anterior NUMERIC;
BEGIN
    -- Alunos dezembro
    SELECT SUM(alunos_pagantes) INTO v_alunos_atual FROM dados_mensais WHERE ano = p_ano_atual AND mes = 12;
    SELECT SUM(alunos_pagantes) INTO v_alunos_anterior FROM dados_mensais WHERE ano = p_ano_anterior AND mes = 12;
    
    -- Matrículas total
    SELECT SUM(novas_matriculas) INTO v_matriculas_atual FROM dados_mensais WHERE ano = p_ano_atual;
    SELECT SUM(novas_matriculas) INTO v_matriculas_anterior FROM dados_mensais WHERE ano = p_ano_anterior;
    
    -- Evasões total
    SELECT SUM(evasoes) INTO v_evasoes_atual FROM dados_mensais WHERE ano = p_ano_atual;
    SELECT SUM(evasoes) INTO v_evasoes_anterior FROM dados_mensais WHERE ano = p_ano_anterior;
    
    -- Churn médio
    SELECT ROUND(AVG(churn_rate), 2) INTO v_churn_atual FROM dados_mensais WHERE ano = p_ano_atual;
    SELECT ROUND(AVG(churn_rate), 2) INTO v_churn_anterior FROM dados_mensais WHERE ano = p_ano_anterior;
    
    -- Ticket médio
    SELECT ROUND(AVG(ticket_medio), 2) INTO v_ticket_atual FROM dados_mensais WHERE ano = p_ano_atual;
    SELECT ROUND(AVG(ticket_medio), 2) INTO v_ticket_anterior FROM dados_mensais WHERE ano = p_ano_anterior;
    
    RETURN QUERY
    SELECT 'alunos'::VARCHAR, v_alunos_anterior::NUMERIC, v_alunos_atual::NUMERIC, 
           calcular_variacao(v_alunos_atual, v_alunos_anterior)
    UNION ALL
    SELECT 'matriculas'::VARCHAR, v_matriculas_anterior::NUMERIC, v_matriculas_atual::NUMERIC,
           calcular_variacao(v_matriculas_atual, v_matriculas_anterior)
    UNION ALL
    SELECT 'evasoes'::VARCHAR, v_evasoes_anterior::NUMERIC, v_evasoes_atual::NUMERIC,
           calcular_variacao(v_evasoes_atual, v_evasoes_anterior)
    UNION ALL
    SELECT 'churn'::VARCHAR, v_churn_anterior::NUMERIC, v_churn_atual::NUMERIC,
           (v_churn_atual - v_churn_anterior)
    UNION ALL
    SELECT 'ticket'::VARCHAR, v_ticket_anterior::NUMERIC, v_ticket_atual::NUMERIC,
           calcular_variacao(v_ticket_atual, v_ticket_anterior);
END;
$function$

CREATE OR REPLACE FUNCTION public.get_dados_comercial_ia(p_unidade_id uuid, p_ano integer, p_mes integer)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result JSONB;
  v_kpis_atual JSONB;
  v_metas JSONB;
  v_kpis_ano_passado JSONB;
  v_leads_por_canal JSONB;
  v_leads_por_curso JSONB;
  v_professores_matriculadores JSONB;
  v_leads_pendentes JSONB;
  v_experimentais_agendadas JSONB;
  v_motivos_nao_matricula JSONB;
  v_lancamentos_hoje JSONB;
  v_unidade_nome TEXT;
  v_ano_mes_str TEXT;
  v_meta_leads NUMERIC;
  v_meta_experimentais NUMERIC;
  v_meta_matriculas NUMERIC;
  v_meta_ticket NUMERIC;
BEGIN
  v_ano_mes_str := p_ano::text || '-' || LPAD(p_mes::text, 2, '0');
  IF p_unidade_id IS NOT NULL THEN
    SELECT nome INTO v_unidade_nome FROM unidades WHERE id = p_unidade_id;
  END IF;

  SELECT jsonb_build_object(
    'total_leads', COALESCE(total_leads, 0),
    'experimentais_agendadas', COALESCE(experimentais_agendadas, 0),
    'experimentais_realizadas', COALESCE(experimentais_realizadas, 0),
    'novas_matriculas', COALESCE(novas_matriculas, 0),
    'taxa_conversao_lead_exp', COALESCE(taxa_conversao_lead_exp, 0),
    'taxa_conversao_exp_mat', COALESCE(taxa_conversao_exp_mat, 0),
    'taxa_conversao_geral', COALESCE(taxa_conversao_geral, 0),
    'ticket_medio_novos', COALESCE(ticket_medio_novos, 0)
  ) INTO v_kpis_atual
  FROM vw_kpis_comercial_mensal
  WHERE (p_unidade_id IS NULL OR unidade_id = p_unidade_id) AND ano = p_ano AND mes = p_mes;

  SELECT valor INTO v_meta_leads FROM metas_kpi WHERE (p_unidade_id IS NULL OR unidade_id = p_unidade_id) AND ano = p_ano AND mes = p_mes AND tipo = 'leads' LIMIT 1;
  SELECT valor INTO v_meta_experimentais FROM metas_kpi WHERE (p_unidade_id IS NULL OR unidade_id = p_unidade_id) AND ano = p_ano AND mes = p_mes AND tipo = 'experimentais' LIMIT 1;
  SELECT valor INTO v_meta_matriculas FROM metas_kpi WHERE (p_unidade_id IS NULL OR unidade_id = p_unidade_id) AND ano = p_ano AND mes = p_mes AND tipo = 'matriculas' LIMIT 1;
  SELECT valor INTO v_meta_ticket FROM metas_kpi WHERE (p_unidade_id IS NULL OR unidade_id = p_unidade_id) AND ano = p_ano AND mes = p_mes AND tipo = 'ticket_medio' LIMIT 1;

  v_metas := jsonb_build_object('leads_mensais', COALESCE(v_meta_leads, 0), 'experimentais_mensais', COALESCE(v_meta_experimentais, 0), 'matriculas_mensais', COALESCE(v_meta_matriculas, 0), 'ticket_medio', COALESCE(v_meta_ticket, 0));

  SELECT jsonb_build_object('total_leads', COALESCE(total_leads, 0), 'novas_matriculas', COALESCE(novas_matriculas, 0))
  INTO v_kpis_ano_passado FROM vw_kpis_comercial_mensal
  WHERE (p_unidade_id IS NULL OR unidade_id = p_unidade_id) AND ano = p_ano - 1 AND mes = p_mes;

  SELECT COALESCE(jsonb_agg(canal_data), '[]'::jsonb) INTO v_leads_por_canal
  FROM (SELECT jsonb_build_object('canal', canal, 'leads', total_leads, 'matriculas', matriculas) as canal_data
    FROM vw_leads_por_canal WHERE (p_unidade_id IS NULL OR unidade = v_unidade_nome) AND ano_mes = v_ano_mes_str ORDER BY total_leads DESC LIMIT 10) sub;

  SELECT COALESCE(jsonb_agg(curso_data), '[]'::jsonb) INTO v_leads_por_curso
  FROM (SELECT jsonb_build_object('curso', c.nome, 'quantidade', COUNT(*)) as curso_data
    FROM leads l JOIN cursos c ON l.curso_interesse_id = c.id
    WHERE (p_unidade_id IS NULL OR l.unidade_id = p_unidade_id) AND EXTRACT(YEAR FROM l.data_contato) = p_ano AND EXTRACT(MONTH FROM l.data_contato) = p_mes
    GROUP BY c.nome ORDER BY COUNT(*) DESC LIMIT 10) sub;

  SELECT COALESCE(jsonb_agg(prof_data), '[]'::jsonb) INTO v_professores_matriculadores
  FROM (SELECT jsonb_build_object('professor', professor, 'matriculas', matriculas) as prof_data
    FROM vw_performance_professor_experimental WHERE (p_unidade_id IS NULL OR unidade = v_unidade_nome) AND ano_mes = v_ano_mes_str ORDER BY matriculas DESC LIMIT 5) sub;

  SELECT COALESCE(jsonb_agg(lead_data), '[]'::jsonb) INTO v_leads_pendentes
  FROM (SELECT jsonb_build_object('nome', nome, 'dias_sem_contato', (CURRENT_DATE - COALESCE(data_ultimo_contato::date, data_contato))) as lead_data
    FROM leads WHERE (p_unidade_id IS NULL OR unidade_id = p_unidade_id) AND status NOT IN ('convertido', 'perdido')
    AND COALESCE(data_ultimo_contato::date, data_contato) < CURRENT_DATE - 3 ORDER BY data_ultimo_contato ASC NULLS FIRST LIMIT 10) sub;

  SELECT COALESCE(jsonb_agg(exp_data), '[]'::jsonb) INTO v_experimentais_agendadas
  FROM (SELECT jsonb_build_object('data', l.data_experimental, 'aluno', l.nome, 'curso', c.nome) as exp_data
    FROM leads l JOIN cursos c ON l.curso_interesse_id = c.id
    WHERE (p_unidade_id IS NULL OR l.unidade_id = p_unidade_id) AND l.experimental_agendada = true
    AND l.data_experimental BETWEEN CURRENT_DATE AND CURRENT_DATE + 7 ORDER BY l.data_experimental ASC LIMIT 10) sub;

  SELECT COALESCE(jsonb_agg(motivo_data), '[]'::jsonb) INTO v_motivos_nao_matricula
  FROM (SELECT jsonb_build_object('motivo', motivo_nao_matricula, 'quantidade', quantidade) as motivo_data
    FROM vw_motivos_nao_matricula WHERE (p_unidade_id IS NULL OR unidade = v_unidade_nome) AND ano_mes = v_ano_mes_str ORDER BY quantidade DESC LIMIT 5) sub;

  -- Lançamentos de hoje - AGORA lê de leads
  SELECT jsonb_build_object(
    'leads', COALESCE(SUM(CASE WHEN status IN ('novo','agendado') THEN COALESCE(quantidade, 1) ELSE 0 END), 0),
    'experimentais', COALESCE(SUM(CASE WHEN status LIKE 'experimental%' THEN COALESCE(quantidade, 1) ELSE 0 END), 0),
    'matriculas', COALESCE(SUM(CASE WHEN status IN ('matriculado','convertido') THEN COALESCE(quantidade, 1) ELSE 0 END), 0)
  ) INTO v_lancamentos_hoje
  FROM leads WHERE (p_unidade_id IS NULL OR unidade_id = p_unidade_id) AND data_contato = CURRENT_DATE;

  v_result := jsonb_build_object(
    'kpis_atual', COALESCE(v_kpis_atual, '{}'::jsonb), 'metas', v_metas,
    'kpis_ano_passado', COALESCE(v_kpis_ano_passado, '{}'::jsonb),
    'leads_por_canal', COALESCE(v_leads_por_canal, '[]'::jsonb),
    'leads_por_curso', COALESCE(v_leads_por_curso, '[]'::jsonb),
    'professores_matriculadores', COALESCE(v_professores_matriculadores, '[]'::jsonb),
    'leads_pendentes', COALESCE(v_leads_pendentes, '[]'::jsonb),
    'experimentais_agendadas', COALESCE(v_experimentais_agendadas, '[]'::jsonb),
    'motivos_nao_matricula', COALESCE(v_motivos_nao_matricula, '[]'::jsonb),
    'lancamentos_hoje', COALESCE(v_lancamentos_hoje, '{}'::jsonb)
  );
  RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.get_dados_relatorio_gerencial(p_unidade_id uuid DEFAULT NULL::uuid, p_ano integer DEFAULT (EXTRACT(year FROM CURRENT_DATE))::integer, p_mes integer DEFAULT (EXTRACT(month FROM CURRENT_DATE))::integer)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result JSONB;
  v_mes_anterior INTEGER;
  v_ano_mes_anterior INTEGER;
  v_unidade_nome TEXT;
  v_gerente_nome TEXT;
  v_hunter_nome TEXT;
  v_farmers_nomes TEXT[];
  v_tem_dados_mensais BOOLEAN;
  v_start_date DATE;
  v_end_date DATE;
BEGIN
  IF p_mes = 1 THEN
    v_mes_anterior := 12;
    v_ano_mes_anterior := p_ano - 1;
  ELSE
    v_mes_anterior := p_mes - 1;
    v_ano_mes_anterior := p_ano;
  END IF;

  v_start_date := MAKE_DATE(p_ano, p_mes, 1);
  v_end_date := (v_start_date + INTERVAL '1 month' - INTERVAL '1 day')::date;

  IF p_unidade_id IS NOT NULL THEN
    SELECT nome, gerente_nome, hunter_nome, farmers_nomes 
    INTO v_unidade_nome, v_gerente_nome, v_hunter_nome, v_farmers_nomes 
    FROM unidades WHERE id = p_unidade_id;
  ELSE
    v_unidade_nome := 'Consolidado';
    v_gerente_nome := 'Diretoria';
    v_hunter_nome := 'Equipe Comercial';
    v_farmers_nomes := ARRAY['Equipe Administrativa'];
  END IF;

  SELECT EXISTS(
    SELECT 1 FROM dados_mensais dm
    WHERE dm.ano = p_ano AND dm.mes = p_mes
      AND (p_unidade_id IS NULL OR dm.unidade_id = p_unidade_id)
      AND dm.alunos_pagantes IS NOT NULL AND dm.alunos_pagantes > 0
  ) INTO v_tem_dados_mensais;

  v_result := jsonb_build_object(
    'periodo', jsonb_build_object(
      'ano', p_ano, 'mes', p_mes,
      'mes_nome', TO_CHAR(TO_DATE(p_mes::TEXT, 'MM'), 'TMMonth'),
      'unidade_id', p_unidade_id, 'unidade_nome', v_unidade_nome
    ),
    'gerente_nome', COALESCE(v_gerente_nome, 'N/D'),
    'hunter_nome', COALESCE(v_hunter_nome, 'N/D'),
    'farmers_nomes', COALESCE(v_farmers_nomes, ARRAY['N/D'])
  );

  -- KPIs de Gestão: dados_mensais para meses fechados, view para mês atual
  IF v_tem_dados_mensais THEN
    v_result := v_result || jsonb_build_object('kpis_gestao', (
      SELECT COALESCE(jsonb_agg(jsonb_build_object(
        'ano', dm.ano, 'mes', dm.mes, 'unidade_id', dm.unidade_id,
        'total_alunos_ativos', COALESCE(dm.alunos_ativos, dm.alunos_pagantes, 0),
        'total_alunos_pagantes', COALESCE(dm.alunos_pagantes, 0),
        'total_bolsistas_integrais', 0, 'total_bolsistas_parciais', 0,
        'ticket_medio', COALESCE(dm.ticket_medio, 0),
        'mrr', COALESCE(dm.faturamento_estimado, 0),
        'churn_rate', COALESCE(dm.churn_rate, 0),
        'inadimplencia_pct', COALESCE(dm.inadimplencia, 0),
        'tempo_permanencia_medio', COALESCE(dm.tempo_permanencia, 0),
        'ltv_medio', COALESCE(dm.tempo_permanencia, 0) * COALESCE(dm.ticket_medio, 0),
        'novas_matriculas', COALESCE(dm.novas_matriculas, 0),
        'total_evasoes', COALESCE(dm.evasoes, 0),
        'reajuste_medio', COALESCE(dm.reajuste_parcelas, 0),
        'faturamento_previsto', COALESCE(dm.faturamento_estimado, 0),
        'faturamento_realizado', COALESCE(dm.faturamento_estimado, 0)
      )), '[]'::jsonb)
      FROM dados_mensais dm
      WHERE dm.ano = p_ano AND dm.mes = p_mes
        AND (p_unidade_id IS NULL OR dm.unidade_id = p_unidade_id)
    ));
  ELSE
    v_result := v_result || jsonb_build_object('kpis_gestao', (
      SELECT COALESCE(jsonb_agg(row_to_json(kg)::jsonb), '[]'::jsonb)
      FROM vw_kpis_gestao_mensal kg
      WHERE (p_unidade_id IS NULL OR kg.unidade_id = p_unidade_id)
        AND kg.ano = p_ano AND kg.mes = p_mes
    ));
  END IF;

  -- KPIs Retenção
  v_result := v_result || jsonb_build_object('kpis_retencao', (
    SELECT COALESCE(jsonb_agg(row_to_json(kr)::jsonb), '[]'::jsonb)
    FROM vw_kpis_retencao_mensal kr
    WHERE (p_unidade_id IS NULL OR kr.unidade_id = p_unidade_id)
      AND kr.ano = p_ano AND kr.mes = p_mes
  ));

  -- KPIs Comerciais: sempre buscar das tabelas base (leads) para qualquer mês
  v_result := v_result || jsonb_build_object('kpis_comercial', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'ano', p_ano, 'mes', p_mes, 'unidade_id', sub.unidade_id,
      'total_leads', sub.total_leads,
      'experimentais_agendadas', sub.exp_agendadas,
      'experimentais_realizadas', sub.exp_realizadas,
      'novas_matriculas', sub.matriculas,
      'faltaram', sub.faltaram,
      'taxa_showup', CASE WHEN sub.exp_agendadas > 0 THEN ROUND(sub.exp_realizadas::numeric / sub.exp_agendadas * 100, 1) ELSE 0 END,
      'taxa_conversao_lead_exp', CASE WHEN sub.total_leads > 0 THEN ROUND(sub.exp_realizadas::numeric / sub.total_leads * 100, 1) ELSE 0 END,
      'taxa_conversao_exp_mat', CASE WHEN sub.exp_realizadas > 0 THEN ROUND(sub.matriculas::numeric / sub.exp_realizadas * 100, 1) ELSE 0 END,
      'taxa_conversao_geral', CASE WHEN sub.total_leads > 0 THEN ROUND(sub.matriculas::numeric / sub.total_leads * 100, 1) ELSE 0 END,
      'faturamento_novos', 0, 'ticket_medio_novos', 0
    )), '[]'::jsonb)
    FROM (
      SELECT 
        COALESCE(l.unidade_id, p_unidade_id) as unidade_id,
        COUNT(*) as total_leads,
        COUNT(*) FILTER (WHERE l.status IN ('experimental_agendada', 'experimental_realizada', 'matriculado', 'convertido')) as exp_agendadas,
        COUNT(*) FILTER (WHERE l.status IN ('experimental_realizada', 'matriculado', 'convertido')) as exp_realizadas,
        COUNT(*) FILTER (WHERE l.status IN ('matriculado', 'convertido')) as matriculas,
        COUNT(*) FILTER (WHERE l.status = 'experimental_faltou') as faltaram
      FROM leads l
      WHERE l.data_contato >= v_start_date AND l.data_contato <= v_end_date
        AND (p_unidade_id IS NULL OR l.unidade_id = p_unidade_id)
      GROUP BY l.unidade_id
    ) sub
  ));

  -- Metas
  v_result := v_result || jsonb_build_object('metas_kpi', (
    SELECT COALESCE(jsonb_object_agg(mk.tipo, mk.valor), '{}'::jsonb)
    FROM metas_kpi mk
    WHERE mk.ano = p_ano AND mk.mes = p_mes
      AND (p_unidade_id IS NULL OR mk.unidade_id = p_unidade_id)
  ));

  -- Matrículas detalhadas
  v_result := v_result || jsonb_build_object(
    'matriculas_ativas', (SELECT COUNT(*) FROM alunos a WHERE a.status = 'ativo' AND (p_unidade_id IS NULL OR a.unidade_id = p_unidade_id)),
    'matriculas_banda', (SELECT COUNT(*) FROM alunos a JOIN cursos c ON a.curso_id = c.id WHERE a.status = 'ativo' AND c.nome ILIKE '%banda%' AND (p_unidade_id IS NULL OR a.unidade_id = p_unidade_id)),
    'matriculas_2_curso', (SELECT COUNT(*) FROM alunos a WHERE a.status = 'ativo' AND a.is_segundo_curso = true AND (p_unidade_id IS NULL OR a.unidade_id = p_unidade_id)),
    'total_bolsistas', (SELECT COUNT(*) FROM alunos a WHERE a.status = 'ativo' AND a.classificacao IN ('bolsista_integral', 'bolsista_parcial') AND (p_unidade_id IS NULL OR a.unidade_id = p_unidade_id))
  );

  -- Mês anterior
  v_result := v_result || jsonb_build_object('mes_anterior', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'alunos_pagantes', dm.alunos_pagantes, 'churn_rate', dm.churn_rate, 'ticket_medio', dm.ticket_medio,
      'taxa_renovacao', dm.taxa_renovacao, 'inadimplencia', dm.inadimplencia, 'tempo_permanencia', dm.tempo_permanencia,
      'reajuste_parcelas', dm.reajuste_parcelas, 'novas_matriculas', dm.novas_matriculas, 'evasoes', dm.evasoes,
      'faturamento_estimado', dm.faturamento_estimado
    )), '[]'::jsonb)
    FROM dados_mensais dm WHERE dm.ano = v_ano_mes_anterior AND dm.mes = v_mes_anterior
      AND (p_unidade_id IS NULL OR dm.unidade_id = p_unidade_id)
  ));

  -- Mesmo mês ano passado
  v_result := v_result || jsonb_build_object('mesmo_mes_ano_passado', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'alunos_pagantes', dm.alunos_pagantes, 'churn_rate', dm.churn_rate, 'ticket_medio', dm.ticket_medio,
      'taxa_renovacao', dm.taxa_renovacao, 'inadimplencia', dm.inadimplencia, 'tempo_permanencia', dm.tempo_permanencia,
      'reajuste_parcelas', dm.reajuste_parcelas, 'novas_matriculas', dm.novas_matriculas, 'evasoes', dm.evasoes,
      'faturamento_estimado', dm.faturamento_estimado, 'saldo_liquido', dm.saldo_liquido
    )), '[]'::jsonb)
    FROM dados_mensais dm WHERE dm.ano = p_ano - 1 AND dm.mes = p_mes
      AND (p_unidade_id IS NULL OR dm.unidade_id = p_unidade_id)
  ));

  -- Sazonalidade
  v_result := v_result || jsonb_build_object('sazonalidade', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'ano', sub.ano, 'novas_matriculas', sub.novas_matriculas, 'evasoes', sub.evasoes,
      'churn_rate', sub.churn_rate, 'saldo_liquido', sub.saldo_liquido
    )), '[]'::jsonb)
    FROM (SELECT s.ano, s.novas_matriculas, s.evasoes, s.churn_rate, s.saldo_liquido
      FROM vw_sazonalidade s WHERE s.mes = p_mes AND s.ano >= p_ano - 3 AND s.ano < p_ano
        AND (p_unidade_id IS NULL OR s.unidade = v_unidade_nome) ORDER BY s.ano DESC) sub
  ));

  -- Motivos evasão
  v_result := v_result || jsonb_build_object('motivos_evasao', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'motivo', sub.motivo_categoria, 'quantidade', sub.quantidade, 'percentual', sub.percentual
    )), '[]'::jsonb)
    FROM (SELECT em.motivo_categoria, em.quantidade, em.percentual FROM vw_evasoes_motivos em
      WHERE (p_unidade_id IS NULL OR em.unidade = v_unidade_nome) ORDER BY em.quantidade DESC LIMIT 5) sub
  ));

  -- Rankings
  v_result := v_result || jsonb_build_object('top_professores_retencao', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'professor', sub.professor, 'tempo_medio_permanencia', sub.tempo_medio_permanencia,
      'presenca_media', sub.presenca_media, 'total_alunos', sub.total_alunos
    )), '[]'::jsonb)
    FROM (SELECT pr.professor, pr.tempo_medio_permanencia, pr.presenca_media, pr.total_alunos
      FROM vw_ranking_professores_retencao pr WHERE (p_unidade_id IS NULL OR pr.unidade = v_unidade_nome)
      ORDER BY pr.tempo_medio_permanencia::numeric DESC LIMIT 3) sub
  ));

  v_result := v_result || jsonb_build_object('top_professores_matriculadores', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'professor_nome', sub.professor_nome, 'matriculas', sub.matriculas,
      'experimentais', sub.experimentais, 'taxa_conversao', sub.taxa_conversao
    )), '[]'::jsonb)
    FROM (SELECT pm.professor_nome, pm.matriculas, pm.experimentais, pm.taxa_conversao
      FROM vw_kpis_professor_mensal pm WHERE pm.ano = p_ano AND pm.mes = p_mes
        AND (p_unidade_id IS NULL OR pm.unidade_id = p_unidade_id) AND pm.matriculas > 0
      ORDER BY pm.matriculas DESC NULLS LAST LIMIT 3) sub
  ));

  v_result := v_result || jsonb_build_object('top_professores_presenca', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'professor', sub.professor, 'presenca_media', sub.presenca_media, 'total_alunos', sub.total_alunos
    )), '[]'::jsonb)
    FROM (SELECT pr.professor, pr.presenca_media, pr.total_alunos
      FROM vw_ranking_professores_retencao pr WHERE (p_unidade_id IS NULL OR pr.unidade = v_unidade_nome)
        AND pr.total_alunos >= 5 ORDER BY pr.presenca_media::numeric DESC LIMIT 3) sub
  ));

  v_result := v_result || jsonb_build_object('top_professores_media_turma', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'professor', sub.professor, 'media_alunos_turma', sub.media_alunos_turma,
      'total_turmas', sub.total_turmas, 'total_alunos', sub.total_alunos
    )), '[]'::jsonb)
    FROM (
      WITH tp AS (
        SELECT p.id as pid, p.nome as professor, a.dia_aula, a.horario_aula, COUNT(*) as cnt
        FROM professores p INNER JOIN alunos a ON a.professor_atual_id = p.id
        WHERE a.status = 'ativo' AND (p_unidade_id IS NULL OR a.unidade_id = p_unidade_id)
          AND a.dia_aula IS NOT NULL AND a.horario_aula IS NOT NULL
        GROUP BY p.id, p.nome, a.dia_aula, a.horario_aula
      )
      SELECT professor, ROUND(AVG(cnt), 1) as media_alunos_turma, COUNT(*) as total_turmas, SUM(cnt) as total_alunos
      FROM tp GROUP BY pid, professor ORDER BY media_alunos_turma DESC LIMIT 3
    ) sub
  ));

  -- Cursos, Canais, Indicações, Family, Permanência, Dados mês atual
  v_result := v_result || jsonb_build_object('cursos_mais_procurados', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object('curso', sub.curso, 'total_alunos', sub.total_alunos)), '[]'::jsonb)
    FROM (SELECT c.nome as curso, COUNT(*) as total_alunos FROM alunos a JOIN cursos c ON a.curso_id = c.id
      WHERE a.status = 'ativo' AND (p_unidade_id IS NULL OR a.unidade_id = p_unidade_id)
      GROUP BY c.nome ORDER BY COUNT(*) DESC LIMIT 5) sub
  ));

  v_result := v_result || jsonb_build_object('canais_maior_conversao', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'canal', sub.canal, 'total_leads', sub.total_leads, 'matriculas', sub.matriculas, 'taxa_conversao', sub.taxa_conversao
    )), '[]'::jsonb)
    FROM (SELECT co.nome as canal, COUNT(*) as total_leads,
        SUM(CASE WHEN l.converteu = true THEN 1 ELSE 0 END) as matriculas,
        ROUND(SUM(CASE WHEN l.converteu = true THEN 1 ELSE 0 END)::numeric / NULLIF(COUNT(*), 0) * 100, 1) as taxa_conversao
      FROM leads l JOIN canais_origem co ON l.canal_origem_id = co.id
      WHERE l.data_contato >= (CURRENT_DATE - INTERVAL '12 months') AND (p_unidade_id IS NULL OR l.unidade_id = p_unidade_id)
      GROUP BY co.nome HAVING COUNT(*) >= 5 ORDER BY taxa_conversao DESC NULLS LAST LIMIT 3) sub
  ));

  v_result := v_result || jsonb_build_object(
    'total_indicacoes', (SELECT COUNT(*) FROM leads l JOIN canais_origem co ON l.canal_origem_id = co.id
      WHERE co.nome = 'Indicação' AND l.converteu = true AND EXTRACT(YEAR FROM l.data_conversao) = p_ano
        AND EXTRACT(MONTH FROM l.data_conversao) = p_mes AND (p_unidade_id IS NULL OR l.unidade_id = p_unidade_id)),
    'total_family_pacotes', (SELECT COUNT(*) FROM alunos a WHERE a.status = 'ativo' AND a.is_segundo_curso = true
      AND a.data_matricula >= v_start_date AND a.data_matricula < v_start_date + INTERVAL '1 month'
      AND (p_unidade_id IS NULL OR a.unidade_id = p_unidade_id))
  );

  v_result := v_result || jsonb_build_object('permanencia_por_faixa', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object('faixa', sub.faixa, 'quantidade', sub.quantidade, 'percentual', sub.percentual) ORDER BY sub.ordem), '[]'::jsonb)
    FROM (SELECT CASE WHEN a.tempo_permanencia_meses < 6 THEN '0-6 meses' WHEN a.tempo_permanencia_meses < 12 THEN '6-12 meses'
        WHEN a.tempo_permanencia_meses < 24 THEN '1-2 anos' WHEN a.tempo_permanencia_meses < 36 THEN '2-3 anos' ELSE '3+ anos' END as faixa,
        CASE WHEN a.tempo_permanencia_meses < 6 THEN 1 WHEN a.tempo_permanencia_meses < 12 THEN 2
        WHEN a.tempo_permanencia_meses < 24 THEN 3 WHEN a.tempo_permanencia_meses < 36 THEN 4 ELSE 5 END as ordem,
        COUNT(*)::INTEGER as quantidade, ROUND(COUNT(*) * 100.0 / NULLIF(SUM(COUNT(*)) OVER(), 0), 1)::NUMERIC as percentual
      FROM alunos a WHERE a.status = 'ativo' AND a.classificacao = 'pagante'
        AND (p_unidade_id IS NULL OR a.unidade_id = p_unidade_id) GROUP BY faixa, ordem) sub
  ));

  v_result := v_result || jsonb_build_object('dados_mes_atual', (
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'alunos_pagantes', dm.alunos_pagantes, 'churn_rate', dm.churn_rate, 'ticket_medio', dm.ticket_medio,
      'taxa_renovacao', dm.taxa_renovacao, 'inadimplencia', dm.inadimplencia, 'tempo_permanencia', dm.tempo_permanencia,
      'reajuste_parcelas', dm.reajuste_parcelas, 'novas_matriculas', dm.novas_matriculas, 'evasoes', dm.evasoes,
      'faturamento_estimado', dm.faturamento_estimado, 'saldo_liquido', dm.saldo_liquido
    )), '[]'::jsonb)
    FROM dados_mensais dm WHERE dm.ano = p_ano AND dm.mes = p_mes
      AND (p_unidade_id IS NULL OR dm.unidade_id = p_unidade_id)
  ));

  RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.introspect_schema_lamusic(table_names text[])
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  result JSONB := '[]'::jsonb;
  tbl TEXT;
  cols JSONB;
BEGIN
  FOREACH tbl IN ARRAY table_names LOOP
    SELECT jsonb_agg(jsonb_build_object(
      'column', column_name, 'type', data_type, 'nullable', is_nullable
    )) INTO cols
    FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = tbl;
    result := result || jsonb_build_object('table', tbl, 'columns', COALESCE(cols, '[]'::jsonb));
  END LOOP;
  RETURN result;
END;
$function$

CREATE OR REPLACE FUNCTION public.log_projeto_alteracao()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO projeto_log_alteracoes (projeto_id, acao, descricao, autor_tipo)
    VALUES (NEW.id, 'criado', 'Projeto criado: ' || NEW.nome, 'sistema');
    RETURN NEW;
  ELSIF TG_OP = 'UPDATE' THEN
    -- Log de mudança de status
    IF OLD.status IS DISTINCT FROM NEW.status THEN
      INSERT INTO projeto_log_alteracoes (projeto_id, acao, campo_alterado, valor_anterior, valor_novo, autor_tipo, descricao)
      VALUES (NEW.id, 'status_alterado', 'status', OLD.status, NEW.status, 'sistema', 
              'Status alterado de ' || COALESCE(OLD.status, 'vazio') || ' para ' || NEW.status);
    END IF;
    -- Log de mudança de nome
    IF OLD.nome IS DISTINCT FROM NEW.nome THEN
      INSERT INTO projeto_log_alteracoes (projeto_id, acao, campo_alterado, valor_anterior, valor_novo, autor_tipo, descricao)
      VALUES (NEW.id, 'atualizado', 'nome', OLD.nome, NEW.nome, 'sistema',
              'Nome alterado de "' || OLD.nome || '" para "' || NEW.nome || '"');
    END IF;
    -- Log de arquivamento
    IF OLD.arquivado IS DISTINCT FROM NEW.arquivado THEN
      INSERT INTO projeto_log_alteracoes (projeto_id, acao, campo_alterado, valor_anterior, valor_novo, autor_tipo, descricao)
      VALUES (NEW.id, 'atualizado', 'arquivado', OLD.arquivado::text, NEW.arquivado::text, 'sistema',
              CASE WHEN NEW.arquivado THEN 'Projeto arquivado' ELSE 'Projeto desarquivado' END);
    END IF;
    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    -- Usar BEFORE DELETE para capturar antes da exclusão
    INSERT INTO projeto_log_alteracoes (projeto_id, acao, descricao, autor_tipo)
    VALUES (NULL, 'excluido', 'Projeto excluído: ' || OLD.nome || ' (ID: ' || OLD.id || ')', 'sistema');
    RETURN OLD;
  END IF;
  RETURN NULL;
END;
$function$

CREATE OR REPLACE FUNCTION public.log_tarefa_alteracao()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO projeto_log_alteracoes (projeto_id, tarefa_id, acao, descricao, autor_tipo)
    VALUES (NEW.projeto_id, NEW.id, 'tarefa_criada', 'Tarefa criada: ' || NEW.titulo, 'sistema');
    RETURN NEW;
  ELSIF TG_OP = 'UPDATE' THEN
    IF OLD.status IS DISTINCT FROM NEW.status THEN
      INSERT INTO projeto_log_alteracoes (projeto_id, tarefa_id, acao, campo_alterado, valor_anterior, valor_novo, autor_tipo, descricao)
      VALUES (NEW.projeto_id, NEW.id, 'tarefa_status', 'status', OLD.status, NEW.status, 'sistema',
              'Tarefa "' || NEW.titulo || '": status alterado para ' || NEW.status);
    END IF;
    IF OLD.status != 'concluida' AND NEW.status = 'concluida' THEN
      INSERT INTO projeto_log_alteracoes (projeto_id, tarefa_id, acao, descricao, autor_tipo)
      VALUES (NEW.projeto_id, NEW.id, 'tarefa_concluida', 'Tarefa concluída: ' || NEW.titulo, 'sistema');
    END IF;
    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    BEGIN
      INSERT INTO projeto_log_alteracoes (projeto_id, tarefa_id, acao, descricao, autor_tipo)
      VALUES (OLD.projeto_id, NULL, 'tarefa_excluida', 'Tarefa excluída: ' || OLD.titulo || ' (ID: ' || OLD.id || ')', 'sistema');
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING '[log_tarefa_alteracao] Falha ao registrar delete: %', SQLERRM;
    END;
    RETURN OLD;
  END IF;
  RETURN NULL;
END;
$function$

CREATE OR REPLACE FUNCTION public.mila_check_disponibilidade_visita(p_unidade_id uuid, p_data date, p_horario time without time zone, p_telefone text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_config       public.visitas_config%ROWTYPE;
  v_feriado_nome text;
  v_dia_semana   integer;
  v_hora_inicio  time;
  v_hora_fim     time;
  v_count        integer;
  v_horarios     text[];
BEGIN
  -- 1. Config da unidade
  SELECT * INTO v_config
  FROM public.visitas_config
  WHERE unidade_id = p_unidade_id AND ativo = true;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'disponivel', false,
      'motivo', 'Sistema de visitas nao esta ativo para esta unidade'
    );
  END IF;

  -- 2. Feriado (dia inteiro, sem sugestao de horarios)
  SELECT nome INTO v_feriado_nome
  FROM public.feriados
  WHERE data = p_data AND ativo = true
  LIMIT 1;

  IF FOUND THEN
    RETURN jsonb_build_object(
      'disponivel', false,
      'motivo', format('Escola fechada — %s', v_feriado_nome)
    );
  END IF;

  -- 3. Duplicidade por telefone
  IF p_telefone IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.visitas
    WHERE telefone = p_telefone AND status = 'agendada'
  ) THEN
    RETURN jsonb_build_object(
      'disponivel', false,
      'motivo', 'Voce ja possui uma visita agendada. Um consultor entrara em contato caso precise reagendar.'
    );
  END IF;

  -- 4. Dia da semana → define janela de funcionamento (movido pra antes de hora cheia)
  v_dia_semana := EXTRACT(DOW FROM p_data);

  IF v_dia_semana = 0 THEN
    RETURN jsonb_build_object(
      'disponivel', false,
      'motivo', 'Nao atendemos aos domingos'
    );
  ELSIF v_dia_semana = 6 THEN
    v_hora_inicio := v_config.horario_inicio_sab;
    v_hora_fim    := v_config.horario_fim_sab;
  ELSE
    v_hora_inicio := v_config.horario_inicio_seg_sex;
    v_hora_fim    := v_config.horario_fim_seg_sex;
  END IF;

  -- 5. Calcula horarios livres do dia (uma vez, reaproveita em todos os casos de erro de horario)
  SELECT array_agg(to_char(h::time, 'HH24:MI') ORDER BY h) INTO v_horarios
  FROM generate_series(
    (p_data + v_hora_inicio)::timestamp,
    (p_data + v_hora_fim - interval '1 hour')::timestamp,
    interval '1 hour'
  ) AS h
  WHERE (
    SELECT COUNT(*) FROM public.visitas
    WHERE unidade_id = p_unidade_id
      AND data = p_data
      AND horario = h::time
      AND status IN ('agendada', 'realizada')
  ) < v_config.max_visitas_por_horario;

  -- 6. Hora cheia (agora retorna sugestoes)
  IF EXTRACT(MINUTE FROM p_horario) != 0 OR EXTRACT(SECOND FROM p_horario) != 0 THEN
    RETURN jsonb_build_object(
      'disponivel', false,
      'motivo', 'Apenas horarios cheios sao permitidos (ex: 14:00, 15:00)',
      'horarios_disponiveis', COALESCE(v_horarios, ARRAY[]::text[])
    );
  END IF;

  -- 7. Dentro da janela (agora retorna sugestoes)
  IF p_horario < v_hora_inicio OR p_horario >= v_hora_fim THEN
    RETURN jsonb_build_object(
      'disponivel', false,
      'motivo', format(
        'Horario fora do funcionamento (%s as %s)',
        to_char(v_hora_inicio, 'HH24:MI'),
        to_char(v_hora_fim,    'HH24:MI')
      ),
      'horarios_disponiveis', COALESCE(v_horarios, ARRAY[]::text[])
    );
  END IF;

  -- 8. Conta visitas no mesmo horario (lotado)
  SELECT COUNT(*) INTO v_count
  FROM public.visitas
  WHERE unidade_id = p_unidade_id
    AND data = p_data
    AND horario = p_horario
    AND status IN ('agendada', 'realizada');

  IF v_count >= v_config.max_visitas_por_horario THEN
    RETURN jsonb_build_object(
      'disponivel', false,
      'motivo', format('Horario lotado (%s/%s visitas neste horario)',
                       v_count, v_config.max_visitas_por_horario),
      'horarios_disponiveis', COALESCE(v_horarios, ARRAY[]::text[])
    );
  END IF;

  -- 9. Disponivel
  RETURN jsonb_build_object('disponivel', true);
END;
$function$

CREATE OR REPLACE FUNCTION public.normalize_phone(tel text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF tel IS NULL OR tel = '' THEN RETURN NULL; END IF;
  tel := regexp_replace(tel, '[^0-9]', '', 'g');
  IF NOT tel LIKE '55%' AND length(tel) >= 10 THEN tel := '55' || tel; END IF;
  RETURN tel;
END;
$function$

CREATE OR REPLACE FUNCTION public.normalize_telefone(tel text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE digits TEXT;
BEGIN
  IF tel IS NULL OR TRIM(tel) = '' THEN RETURN NULL; END IF;
  digits := regexp_replace(tel, '\D', '', 'g');
  IF digits = '' THEN RETURN NULL; END IF;
  IF length(digits) IN (10, 11) THEN
    digits := '55' || digits;
  END IF;
  RETURN digits;
END;
$function$

CREATE OR REPLACE FUNCTION public.pode_enviar_pesquisa_evasao(p_evasao_id integer)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_data_evasao DATE;
  v_dias_desde_evasao INTEGER;
BEGIN
  SELECT data INTO v_data_evasao
  FROM movimentacoes_admin
  WHERE id = p_evasao_id;

  IF v_data_evasao IS NULL THEN
    RETURN FALSE;
  END IF;

  v_dias_desde_evasao := CURRENT_DATE - v_data_evasao;
  RETURN v_dias_desde_evasao >= 3;
END;
$function$

