CREATE OR REPLACE FUNCTION public.registrar_venda_legacy(p_produto_id integer, p_unidade_id uuid, p_quantidade integer, p_forma_pagamento character varying, p_via_audit text, p_variacao_id integer DEFAULT NULL::integer, p_tipo_cliente character varying DEFAULT 'avulso'::character varying, p_cliente_nome character varying DEFAULT NULL::character varying, p_aluno_id integer DEFAULT NULL::integer, p_professor_indicador_id integer DEFAULT NULL::integer, p_desconto numeric DEFAULT 0, p_parcelas integer DEFAULT 1, p_observacoes text DEFAULT NULL::text)
 RETURNS TABLE(venda_id integer, saldo_apos integer, comissao_farmer numeric, comissao_professor numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_preco_unit NUMERIC; v_produto_nome VARCHAR; v_variacao_nome VARCHAR;
  v_subtotal NUMERIC; v_total NUMERIC;
  v_saldo_atual INT; v_saldo_novo INT;
  v_venda_id INT;
  v_comissao_farmer_pct NUMERIC; v_comissao_prof_pct NUMERIC;
  v_comissao_farmer NUMERIC := 0; v_comissao_prof NUMERIC := 0;
  v_carteira_id INT;
BEGIN
  IF p_quantidade IS NULL OR p_quantidade <= 0 THEN
    RAISE EXCEPTION 'quantidade_deve_ser_positiva: %', p_quantidade;
  END IF;
  IF p_forma_pagamento NOT IN ('pix','credito','debito','dinheiro') THEN
    RAISE EXCEPTION 'forma_pagamento_invalida: %', p_forma_pagamento;
  END IF;
  IF p_via_audit IS NULL OR LENGTH(TRIM(p_via_audit)) = 0 THEN
    RAISE EXCEPTION 'via_audit_obrigatorio';
  END IF;

  IF p_variacao_id IS NOT NULL THEN
    SELECT preco, nome INTO v_preco_unit, v_variacao_nome
      FROM loja_variacoes WHERE id = p_variacao_id AND ativo = TRUE;
    IF v_preco_unit IS NULL THEN
      RAISE EXCEPTION 'variacao_inexistente_ou_inativa: %', p_variacao_id;
    END IF;
  END IF;
  IF v_preco_unit IS NULL THEN
    SELECT preco, nome INTO v_preco_unit, v_produto_nome
      FROM loja_produtos WHERE id = p_produto_id AND ativo = TRUE;
    IF v_preco_unit IS NULL THEN
      RAISE EXCEPTION 'produto_inexistente_ou_inativo: %', p_produto_id;
    END IF;
  ELSE
    SELECT nome INTO v_produto_nome FROM loja_produtos WHERE id = p_produto_id;
  END IF;

  SELECT quantidade INTO v_saldo_atual FROM loja_estoque
    WHERE produto_id = p_produto_id
      AND unidade_id = p_unidade_id
      AND (variacao_id IS NOT DISTINCT FROM p_variacao_id)
    FOR UPDATE;
  IF v_saldo_atual IS NULL THEN
    RAISE EXCEPTION 'estoque_inexistente_pra_unidade';
  END IF;
  IF v_saldo_atual < p_quantidade THEN
    RAISE EXCEPTION 'estoque_insuficiente: tem %, pediu %', v_saldo_atual, p_quantidade;
  END IF;
  v_saldo_novo := v_saldo_atual - p_quantidade;

  v_subtotal := v_preco_unit * p_quantidade;
  v_total := v_subtotal - COALESCE(p_desconto, 0);

  INSERT INTO loja_vendas (
    unidade_id, data_venda, tipo_cliente, cliente_nome, aluno_id, professor_indicador_id,
    subtotal, desconto, total, forma_pagamento, parcelas, observacoes, status, vendedor_id
  ) VALUES (
    p_unidade_id, NOW(), p_tipo_cliente, p_cliente_nome, p_aluno_id, p_professor_indicador_id,
    v_subtotal, COALESCE(p_desconto, 0), v_total, p_forma_pagamento, p_parcelas,
    CONCAT_WS(' — ', NULLIF(p_observacoes, ''), p_via_audit), 'concluida', NULL
  ) RETURNING id INTO v_venda_id;

  INSERT INTO loja_vendas_itens (
    venda_id, produto_id, variacao_id, produto_nome, variacao_nome,
    quantidade, preco_unitario, subtotal
  ) VALUES (
    v_venda_id, p_produto_id, p_variacao_id, v_produto_nome, v_variacao_nome,
    p_quantidade, v_preco_unit, v_subtotal
  );

  UPDATE loja_estoque SET quantidade = v_saldo_novo, updated_at = NOW()
    WHERE produto_id = p_produto_id
      AND unidade_id = p_unidade_id
      AND (variacao_id IS NOT DISTINCT FROM p_variacao_id);

  INSERT INTO loja_movimentacoes_estoque (
    produto_id, variacao_id, unidade_id, tipo, quantidade,
    saldo_apos, referencia_id, colaborador_id, observacoes
  ) VALUES (
    p_produto_id, p_variacao_id, p_unidade_id, 'venda', -p_quantidade,
    v_saldo_novo, v_venda_id, NULL, p_via_audit
  );

  SELECT (valor::numeric) / 100 INTO v_comissao_farmer_pct
    FROM loja_configuracoes WHERE chave = 'comissao_farmer_padrao';
  SELECT (valor::numeric) / 100 INTO v_comissao_prof_pct
    FROM loja_configuracoes WHERE chave = 'comissao_professor_indicacao';
  v_comissao_farmer_pct := COALESCE(v_comissao_farmer_pct, 0.05);
  v_comissao_prof_pct   := COALESCE(v_comissao_prof_pct,   0.05);

  v_comissao_farmer := v_total * v_comissao_farmer_pct;

  IF p_professor_indicador_id IS NOT NULL THEN
    v_comissao_prof := v_total * v_comissao_prof_pct;
    SELECT id INTO v_carteira_id FROM loja_carteira
      WHERE tipo_titular = 'professor'
        AND professor_id = p_professor_indicador_id
        AND unidade_id = p_unidade_id;
    IF v_carteira_id IS NULL THEN
      INSERT INTO loja_carteira (tipo_titular, professor_id, unidade_id, saldo, moedas_la)
      VALUES ('professor', p_professor_indicador_id, p_unidade_id, v_comissao_prof, 0)
      RETURNING id INTO v_carteira_id;
    ELSE
      UPDATE loja_carteira SET saldo = saldo + v_comissao_prof WHERE id = v_carteira_id;
    END IF;
    INSERT INTO loja_carteira_movimentacoes (
      carteira_id, tipo, valor, saldo_apos, referencia_tipo, referencia_id, descricao
    ) VALUES (
      v_carteira_id, 'credito', v_comissao_prof,
      (SELECT saldo FROM loja_carteira WHERE id = v_carteira_id),
      'venda', v_venda_id,
      CONCAT('Indicação venda #', v_venda_id, ' — ', p_via_audit)
    );
  END IF;

  RETURN QUERY SELECT v_venda_id, v_saldo_novo, v_comissao_farmer, v_comissao_prof;
END;
$function$

CREATE OR REPLACE FUNCTION public.registrar_venda_v2(p_unidade_id uuid, p_itens jsonb, p_forma_pagamento character varying, p_via_audit text, p_tipo_cliente character varying DEFAULT 'avulso'::character varying, p_cliente_nome character varying DEFAULT NULL::character varying, p_aluno_id integer DEFAULT NULL::integer, p_colaborador_cliente_id integer DEFAULT NULL::integer, p_professor_indicador_id integer DEFAULT NULL::integer, p_desconto numeric DEFAULT 0, p_desconto_tipo character varying DEFAULT 'valor'::character varying, p_parcelas integer DEFAULT 1, p_observacoes text DEFAULT NULL::text)
 RETURNS TABLE(venda_id integer, total numeric, itens_resultado jsonb, comissao_professor numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_item JSONB;
  v_produto_id INT;
  v_variacao_id INT;
  v_qtd INT;
  v_preco_unit NUMERIC;
  v_preco_override NUMERIC;
  v_produto_nome VARCHAR;
  v_variacao_nome VARCHAR;
  v_subtotal NUMERIC := 0;
  v_subtotal_item NUMERIC;
  v_saldo_atual INT;
  v_saldo_novo INT;
  v_total NUMERIC;
  v_desconto_calc NUMERIC := 0;
  v_venda_id INT;
  v_itens_result JSONB := '[]'::JSONB;
  v_comissao_prof_pct NUMERIC;
  v_comissao_prof NUMERIC := 0;
  v_carteira_id INT;
BEGIN
  -- Validações
  IF p_itens IS NULL OR jsonb_array_length(p_itens) = 0 THEN
    RAISE EXCEPTION 'itens_vazios';
  END IF;
  IF p_forma_pagamento NOT IN ('pix','dinheiro','debito','credito','folha','saldo') THEN
    RAISE EXCEPTION 'forma_pagamento_invalida: %', p_forma_pagamento;
  END IF;
  IF p_tipo_cliente NOT IN ('aluno','colaborador','avulso') THEN
    RAISE EXCEPTION 'tipo_cliente_invalido: %', p_tipo_cliente;
  END IF;
  IF p_desconto_tipo NOT IN ('valor','percentual') THEN
    RAISE EXCEPTION 'desconto_tipo_invalido: %', p_desconto_tipo;
  END IF;
  IF p_via_audit IS NULL OR LENGTH(TRIM(p_via_audit)) = 0 THEN
    RAISE EXCEPTION 'via_audit_obrigatorio';
  END IF;

  -- LOOP 1: lock + checa saldo de cada item, acumula subtotal
  FOR v_item IN SELECT jsonb_array_elements(p_itens) LOOP
    v_produto_id := (v_item->>'produto_id')::INT;
    v_variacao_id := NULLIF(v_item->>'variacao_id', '')::INT;
    v_qtd := (v_item->>'quantidade')::INT;
    v_preco_override := NULLIF(v_item->>'preco_unitario_override', '')::NUMERIC;

    IF v_qtd IS NULL OR v_qtd <= 0 THEN
      RAISE EXCEPTION 'quantidade_invalida_item: produto=%', v_produto_id;
    END IF;

    IF v_preco_override IS NOT NULL THEN
      v_preco_unit := v_preco_override;
      SELECT nome INTO v_produto_nome FROM loja_produtos WHERE id = v_produto_id;
    ELSIF v_variacao_id IS NOT NULL THEN
      SELECT preco, nome INTO v_preco_unit, v_variacao_nome
        FROM loja_variacoes WHERE id = v_variacao_id AND ativo = TRUE;
      IF v_preco_unit IS NULL THEN
        RAISE EXCEPTION 'variacao_inexistente_ou_inativa: %', v_variacao_id;
      END IF;
      SELECT nome INTO v_produto_nome FROM loja_produtos WHERE id = v_produto_id;
    ELSE
      SELECT preco, nome INTO v_preco_unit, v_produto_nome
        FROM loja_produtos WHERE id = v_produto_id AND ativo = TRUE;
      IF v_preco_unit IS NULL THEN
        RAISE EXCEPTION 'produto_inexistente_ou_inativo: %', v_produto_id;
      END IF;
    END IF;

    SELECT quantidade INTO v_saldo_atual FROM loja_estoque
      WHERE produto_id = v_produto_id
        AND unidade_id = p_unidade_id
        AND (variacao_id IS NOT DISTINCT FROM v_variacao_id)
      FOR UPDATE;
    IF v_saldo_atual IS NULL THEN
      RAISE EXCEPTION 'estoque_inexistente_pra_unidade: produto=%', v_produto_id;
    END IF;
    IF v_saldo_atual < v_qtd THEN
      RAISE EXCEPTION 'estoque_insuficiente: produto=%, tem=%, pediu=%',
        v_produto_id, v_saldo_atual, v_qtd;
    END IF;

    v_subtotal_item := v_preco_unit * v_qtd;
    v_subtotal := v_subtotal + v_subtotal_item;
  END LOOP;

  IF p_desconto_tipo = 'percentual' THEN
    v_desconto_calc := v_subtotal * (p_desconto / 100.0);
  ELSE
    v_desconto_calc := p_desconto;
  END IF;
  v_total := v_subtotal - v_desconto_calc;
  IF v_total < 0 THEN
    RAISE EXCEPTION 'desconto_maior_que_subtotal';
  END IF;

  INSERT INTO loja_vendas (
    unidade_id, data_venda, tipo_cliente, cliente_nome, aluno_id,
    colaborador_cliente_id, professor_indicador_id,
    subtotal, desconto, desconto_tipo, total,
    forma_pagamento, parcelas, observacoes, status, vendedor_id
  ) VALUES (
    p_unidade_id, NOW(), p_tipo_cliente, p_cliente_nome, p_aluno_id,
    p_colaborador_cliente_id, p_professor_indicador_id,
    v_subtotal, v_desconto_calc, p_desconto_tipo, v_total,
    p_forma_pagamento, p_parcelas,
    CONCAT_WS(' — ', NULLIF(p_observacoes, ''), p_via_audit),
    'concluida', NULL
  ) RETURNING id INTO v_venda_id;

  FOR v_item IN SELECT jsonb_array_elements(p_itens) LOOP
    v_produto_id := (v_item->>'produto_id')::INT;
    v_variacao_id := NULLIF(v_item->>'variacao_id', '')::INT;
    v_qtd := (v_item->>'quantidade')::INT;
    v_preco_override := NULLIF(v_item->>'preco_unitario_override', '')::NUMERIC;

    IF v_preco_override IS NOT NULL THEN
      v_preco_unit := v_preco_override;
    ELSIF v_variacao_id IS NOT NULL THEN
      SELECT preco INTO v_preco_unit FROM loja_variacoes WHERE id = v_variacao_id;
    ELSE
      SELECT preco INTO v_preco_unit FROM loja_produtos WHERE id = v_produto_id;
    END IF;
    SELECT nome INTO v_produto_nome FROM loja_produtos WHERE id = v_produto_id;
    v_variacao_nome := NULL;
    IF v_variacao_id IS NOT NULL THEN
      SELECT nome INTO v_variacao_nome FROM loja_variacoes WHERE id = v_variacao_id;
    END IF;

    v_subtotal_item := v_preco_unit * v_qtd;

    INSERT INTO loja_vendas_itens (
      venda_id, produto_id, variacao_id, produto_nome, variacao_nome,
      quantidade, preco_unitario, subtotal
    ) VALUES (
      v_venda_id, v_produto_id, v_variacao_id, v_produto_nome, v_variacao_nome,
      v_qtd, v_preco_unit, v_subtotal_item
    );

    UPDATE loja_estoque SET quantidade = quantidade - v_qtd, updated_at = NOW()
      WHERE produto_id = v_produto_id
        AND unidade_id = p_unidade_id
        AND (variacao_id IS NOT DISTINCT FROM v_variacao_id)
      RETURNING quantidade INTO v_saldo_novo;

    INSERT INTO loja_movimentacoes_estoque (
      produto_id, variacao_id, unidade_id, tipo,
      quantidade, saldo_apos, referencia_id, colaborador_id, observacoes
    ) VALUES (
      v_produto_id, v_variacao_id, p_unidade_id, 'venda',
      -v_qtd, v_saldo_novo, v_venda_id, NULL, p_via_audit
    );

    v_itens_result := v_itens_result || jsonb_build_object(
      'produto_id', v_produto_id,
      'variacao_id', v_variacao_id,
      'quantidade', v_qtd,
      'saldo_apos', v_saldo_novo
    );
  END LOOP;

  IF p_professor_indicador_id IS NOT NULL THEN
    SELECT (valor::numeric) / 100 INTO v_comissao_prof_pct
      FROM loja_configuracoes WHERE chave = 'comissao_professor_indicacao';
    v_comissao_prof_pct := COALESCE(v_comissao_prof_pct, 0.05);
    v_comissao_prof := v_total * v_comissao_prof_pct;

    SELECT id INTO v_carteira_id FROM loja_carteira
      WHERE tipo_titular = 'professor'
        AND professor_id = p_professor_indicador_id
        AND unidade_id = p_unidade_id;
    IF v_carteira_id IS NULL THEN
      INSERT INTO loja_carteira (tipo_titular, professor_id, unidade_id, saldo, moedas_la)
      VALUES ('professor', p_professor_indicador_id, p_unidade_id, v_comissao_prof, 0)
      RETURNING id INTO v_carteira_id;
    ELSE
      UPDATE loja_carteira SET saldo = saldo + v_comissao_prof WHERE id = v_carteira_id;
    END IF;
    INSERT INTO loja_carteira_movimentacoes (
      carteira_id, tipo, valor, saldo_apos, referencia_tipo, referencia_id, descricao
    ) VALUES (
      v_carteira_id, 'credito', v_comissao_prof,
      (SELECT saldo FROM loja_carteira WHERE id = v_carteira_id),
      'venda', v_venda_id,
      CONCAT('Indicacao venda #', v_venda_id, ' — ', p_via_audit)
    );
  END IF;

  RETURN QUERY SELECT v_venda_id, v_total, v_itens_result, v_comissao_prof;
END;
$function$

CREATE OR REPLACE FUNCTION public.resetar_teste_mila(p_lead_id integer)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_conversa_id uuid;
  v_msgs_deletadas int;
  v_buffer_deletado int;
BEGIN
  SELECT id INTO v_conversa_id FROM crm_conversas WHERE lead_id = p_lead_id LIMIT 1;

  IF v_conversa_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Conversa não encontrada para este lead');
  END IF;

  DELETE FROM crm_mensagens WHERE conversa_id = v_conversa_id;
  GET DIAGNOSTICS v_msgs_deletadas = ROW_COUNT;

  DELETE FROM mila_message_buffer WHERE conversa_id = v_conversa_id;
  GET DIAGNOSTICS v_buffer_deletado = ROW_COUNT;

  UPDATE crm_conversas SET
    status = 'aberta', atribuido_a = 'mila', mila_pausada = false,
    mila_pausada_em = NULL, mila_pausada_por = NULL, nao_lidas = 0,
    ultima_mensagem_at = NULL, ultima_mensagem_preview = NULL, updated_at = NOW()
  WHERE id = v_conversa_id;

  UPDATE leads SET
    status = 'novo', etapa_pipeline_id = 1, temperatura = NULL,
    curso_interesse_id = NULL, canal_origem_id = NULL, faixa_etaria = NULL,
    experimental_agendada = false, data_experimental = NULL, horario_experimental = NULL,
    professor_experimental_id = NULL, experimental_realizada = false,
    faltou_experimental = false, converteu = false, data_conversao = NULL,
    qtd_mensagens_mila = 0, qtd_tentativas_sem_resposta = 0,
    data_passagem_mila = NULL, motivo_passagem_mila = NULL,
    observacoes = NULL, updated_at = NOW()
  WHERE id = p_lead_id;

  RETURN jsonb_build_object(
    'success', true, 'mensagens_deletadas', v_msgs_deletadas,
    'buffer_deletado', v_buffer_deletado, 'conversa_id', v_conversa_id
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.rpc_marcar_inadimplentes()
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  resultado JSON;
  dia_atual INTEGER := EXTRACT(day FROM CURRENT_DATE)::INTEGER;
  v_total INTEGER;
BEGIN
  UPDATE alunos a
  SET status_pagamento = 'inadimplente',
      updated_at = NOW()
  WHERE a.status IN ('ativo', 'trancado')
    AND a.dia_vencimento <= dia_atual
    AND (a.status_pagamento IS NULL OR a.status_pagamento = 'em_dia')
    AND (a.tipo_matricula_id IS NULL OR a.tipo_matricula_id NOT IN (3, 4, 5))
    AND COALESCE(a.status_pagamento, '') != 'sem_parcela';

  GET DIAGNOSTICS v_total = ROW_COUNT;

  SELECT json_build_object(
    'total_marcados', v_total,
    'dia_atual', dia_atual,
    'executado_em', NOW()
  ) INTO resultado;

  RETURN resultado;
END;
$function$

